    public void testFindMappedFileByOffset() {
        // Precondition 1: Create a mapped file queue
        String storePath = "target/unit_test_store/findByOffset/";
        int mappedFileSize = 1024; // 1024 bytes per file
        MappedFileQueue mappedFileQueue = new MappedFileQueue(storePath, mappedFileSize, null);

        // Precondition 2 & 3: Add 1024 messages of "abcd" (4 bytes each) = 4096 bytes
        // This will create multiple mapped files (4096 / 1024 = 4 files)
        long currentOffset = 0;
        for (int i = 0; i < 1024; i++) {
            MappedFile mappedFile = mappedFileQueue.getLastMappedFile(currentOffset);
            // Simulate writing 4 bytes. In a real test, you would write to the mappedFile's ByteBuffer.
            // For this test, we just ensure files are created.
            currentOffset += 4;
        }

        // Expected Result 1: Correctly find mapped file for offsets within the first file
        MappedFile firstFile = mappedFileQueue.findMappedFileByOffset(0);
        assertThat(firstFile).isNotNull();
