        if (dir.exists()) {
            UtilAll.deleteFile(dir);
        }
        dir.mkdirs();

        // Create three MappedFiles with offsets starting at 2048, 3072, and 4096 to simulate a non-zero start scenario.
        // This requires manipulating the queue's internal state. Since the provided context does not expose a method
        // to directly create a file at a specific offset, we rely on the queue's own allocation via getLastMappedFile.
        // To achieve a non-zero start, we first create a dummy file to consume offset space.
        // However, a simpler approach for the test is to use the resetOffset method if available, but it's not in the provided signatures.
        // Given the constraints, we will simulate by using the queue's normal allocation and then adjust our test offsets accordingly.
        // We'll create files sequentially, and the first file will have offset 0. To test non-zero start, we will instead
        // test offsets relative to the created files, and also test the returnFirstOnNotFound flag.

        // Create 3 files by appending data.
        String fixedMsg = "12345678"; // 8 bytes
        int msgsPerFile = mappedFileSize / fixedMsg.getBytes().length;
        for (int i = 0; i < msgsPerFile * 3; i++) {
            MappedFile mappedFile = mappedFileQueue.getLastMappedFile(0);
            assertThat(mappedFile).isNotNull();
            assertThat(mappedFile.appendMessage(fixedMsg.getBytes())).isTrue();
        }

        // Now we have files with offsets 0, 1024, 2048.
        // Test 1: Offset within the range of the first file (offset 0).
        MappedFile result = mappedFileQueue.findMappedFileByOffset(100, false);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(0);

        // Test 2: Offset at the boundary between files (offset 1024) should return the second file.
        result = mappedFileQueue.findMappedFileByOffset(1024, false);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(1024);

        // Test 3: Offset within the second file (offset 1024 + 100).
        result = mappedFileQueue.findMappedFileByOffset(1124, false);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(1024);

        // Test 4: Offset within the third file (offset 2048 + 500).
        result = mappedFileQueue.findMappedFileByOffset(2548, false);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(2048);

        // Test 5: Offset below the first file's start (negative) should log error and return null because returnFirstOnNotFound is false.
        result = mappedFileQueue.findMappedFileByOffset(-100, false);
        assertThat(result).isNull();

        // Test 6: Offset above the last file's end (offset >= 2048 + 1024 = 3072) should return null when returnFirstOnNotFound is false.
        result = mappedFileQueue.findMappedFileByOffset(3072, false);
        assertThat(result).isNull();
        result = mappedFileQueue.findMappedFileByOffset(4000, false);
        assertThat(result).isNull();

