        result = mappedFileQueue.findMappedFileByOffset(4000, true);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(0); // Should return first file.

        // Test 8: Offset below the first file's start with returnFirstOnNotFound = true should return the first file.
        result = mappedFileQueue.findMappedFileByOffset(-100, true);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(0);

        // Test 9: Offset exactly at the last byte of the last file (offset = 2048 + 1023) should return the third file.
        result = mappedFileQueue.findMappedFileByOffset(3071, false);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(2048);

        // Test 10: Offset at the very start of the queue (offset 0) should return the first file.
        result = mappedFileQueue.findMappedFileByOffset(0, false);
        assertThat(result).isNotNull();
        assertThat(result.getFileFromOffset()).isEqualTo(0);

        // Cleanup
        mappedFileQueue.shutdown(1000);
        mappedFileQueue.destroy();
        if (dir.exists()) {
            UtilAll.deleteFile(dir);
        }
    }

