    public void buildIndex(DispatchRequest req) {
        //创建IndexFile并开启后台线程刷新IndexFile
        IndexFile indexFile = retryGetAndCreateIndexFile();
        if (indexFile != null) {
            long endPhyOffset = indexFile.getEndPhyOffset();
